"""Expression evaluator for pipeline success/requires blocks."""

import os
import re
from typing import Any, Dict, List

from ast_nodes import (
    ASTNode, Literal, Identifier, BinaryOp, UnaryOp, ArrayAccess,
    FunctionCall, TaskCall, TemplateString, ListLiteral, ParameterAccess,
    WorkspaceAccess, VarDecl, Assignment, IfStatement, ForStatement,
    WhileStatement, ReturnStatement, BreakStatement, ContinueStatement,
    ExpressionStatement, FailsTask,
)


class ReturnValue(Exception):
    def __init__(self, value: Any):
        self.value = value


class BreakSignal(Exception):
    pass


class ContinueSignal(Exception):
    pass


class EvaluationError(Exception):
    def __init__(self, message: str):
        self.message = message
        super().__init__(f"INVALID_PIPE: {message}")


class ExprEvaluator:
    """Evaluates expressions in the pipeline context."""

    def __init__(self, variables: Dict[str, Any] = None, env_vars: Dict[str, str] = None,
                 stdout: str = "", stderr: str = "", exit_code: int = 0,
                 output_dir: str = None, workspace: str = None):
        self.variables = variables or {}
        self.env_vars = env_vars or {}
        self.stdout = stdout
        self.stderr = stderr
        self.exit_code = exit_code
        self.output_dir = output_dir
        self.workspace = workspace

    def evaluate_statements(self, statements: List[ASTNode]) -> Any:
        result = None
        for stmt in statements:
            result = self.evaluate_statement(stmt)
        return result

    def evaluate_statement(self, stmt: ASTNode) -> Any:
        if isinstance(stmt, ReturnStatement):
            raise ReturnValue(self.evaluate_expr(stmt.value) if stmt.value else None)
        if isinstance(stmt, BreakStatement):
            raise BreakSignal()
        if isinstance(stmt, ContinueStatement):
            raise ContinueSignal()
        if isinstance(stmt, VarDecl):
            value = self.evaluate_expr(stmt.value) if stmt.value else self.default_for_type(stmt.var_type)
            self.variables[stmt.var_name] = value
            return value
        if isinstance(stmt, Assignment):
            return self._do_assignment(stmt)
        if isinstance(stmt, IfStatement):
            return self.evaluate_if(stmt)
        if isinstance(stmt, ForStatement):
            return self.evaluate_for(stmt)
        if isinstance(stmt, WhileStatement):
            return self.evaluate_while(stmt)
        if isinstance(stmt, ExpressionStatement):
            return self.evaluate_expr(stmt.expression)
        if isinstance(stmt, FailsTask):
            return stmt
        return self.evaluate_expr(stmt)

    def _do_assignment(self, stmt: Assignment) -> Any:
        value = self.evaluate_expr(stmt.value) if hasattr(stmt, 'value') and stmt.value else None
        if isinstance(stmt.name, Identifier):
            self.variables[stmt.name.name] = value
        elif isinstance(stmt.name, ArrayAccess):
            arr = self.evaluate_expr(stmt.name.array)
            idx = self.evaluate_expr(stmt.name.index)
            arr[int(idx)] = value
        return value

    def evaluate_if(self, stmt: IfStatement) -> Any:
        if self.is_truthy(self.evaluate_expr(stmt.condition)):
            return self.evaluate_statements(stmt.then_block)

        for elif_cond, elif_block in stmt.elif_clauses:
            if self.is_truthy(self.evaluate_expr(elif_cond)):
                return self.evaluate_statements(elif_block)

        if stmt.else_block:
            return self.evaluate_statements(stmt.else_block)
        return None

    def evaluate_for(self, stmt: ForStatement) -> Any:
        if stmt.is_foreach:
            iterable = self.evaluate_expr(stmt.iterable)
            for item in iterable:
                self.variables[stmt.var_name] = item
                try:
                    self.evaluate_statements(stmt.body)
                except BreakSignal:
                    break
                except ContinueSignal:
                    continue
            return None

        if stmt.init:
            self.evaluate_statement(stmt.init)

        while True:
            if stmt.condition and not self.is_truthy(self.evaluate_expr(stmt.condition)):
                break
            try:
                self.evaluate_statements(stmt.body)
            except BreakSignal:
                break
            except ContinueSignal:
                pass
            if stmt.update:
                self.evaluate_expr(stmt.update)
        return None

    def evaluate_while(self, stmt: WhileStatement) -> Any:
        while self.is_truthy(self.evaluate_expr(stmt.condition)):
            try:
                self.evaluate_statements(stmt.body)
            except BreakSignal:
                break
            except ContinueSignal:
                continue
        return None

    def evaluate_expr(self, expr: ASTNode) -> Any:
        if isinstance(expr, Literal):
            return expr.value
        if isinstance(expr, Identifier):
            return self._resolve_identifier(expr.name)
        if isinstance(expr, ParameterAccess):
            if 'params' in self.variables and expr.param_name in self.variables['params']:
                return self.variables['params'][expr.param_name]
            raise EvaluationError(f"Undefined parameter: {expr.param_name}")
        if isinstance(expr, WorkspaceAccess):
            return self.workspace or os.getcwd()
        if isinstance(expr, BinaryOp):
            return self.evaluate_binary_op(expr)
        if isinstance(expr, UnaryOp):
            return self.evaluate_unary_op(expr)
        if isinstance(expr, ArrayAccess):
            arr = self.evaluate_expr(expr.array)
            idx = self.evaluate_expr(expr.index)
            if isinstance(arr, (list, str)):
                return arr[int(idx)]
            raise EvaluationError(f"Cannot index into {type(arr)}")
        if isinstance(expr, FunctionCall):
            return self.evaluate_function(expr)
        if isinstance(expr, (TaskCall, FailsTask)):
            return expr
        if isinstance(expr, TemplateString):
            return self.evaluate_template_string(expr)
        if isinstance(expr, ListLiteral):
            return [self.evaluate_expr(e) for e in expr.elements]
        raise EvaluationError(f"Cannot evaluate expression: {type(expr).__name__}")

    def _resolve_identifier(self, name: str) -> Any:
        special = {'stdout': self.stdout, 'stderr': self.stderr, 'exit_code': self.exit_code}
        if name in special:
            return special[name]
        if name in self.variables:
            return self.variables[name]
        if name in self.env_vars:
            return self.env_vars[name]
        raise EvaluationError(f"Undefined variable: {name}")

    def evaluate_binary_op(self, expr: BinaryOp) -> Any:
        left = self.evaluate_expr(expr.left)

        # Short-circuit logical operators
        if expr.op == '&&':
            return self.is_truthy(left) and self.is_truthy(self.evaluate_expr(expr.right))
        if expr.op == '||':
            return self.is_truthy(left) or self.is_truthy(self.evaluate_expr(expr.right))

        right = self.evaluate_expr(expr.right)

        if expr.op == '+':
            return left + right
        if expr.op == '-':
            return left - right
        if expr.op == '*':
            return left * right
        if expr.op == '/':
            if right == 0:
                raise EvaluationError("Division by zero")
            return left / right
        if expr.op == '%':
            return self._concat_or_modulo(left, right)

        comparisons = {
            '==': lambda a, b: a == b, '!=': lambda a, b: a != b,
            '<': lambda a, b: a < b, '>': lambda a, b: a > b,
            '<=': lambda a, b: a <= b, '>=': lambda a, b: a >= b,
        }
        if expr.op in comparisons:
            return comparisons[expr.op](left, right)

        raise EvaluationError(f"Unknown operator: {expr.op}")

    @staticmethod
    def _concat_or_modulo(left: Any, right: Any) -> Any:
        if isinstance(left, str) or isinstance(right, str):
            if isinstance(left, list) or isinstance(right, list):
                raise EvaluationError("Cannot convert list to string")
            return str(left) + str(right)
        return left % right

    def evaluate_unary_op(self, expr: UnaryOp) -> Any:
        operand = self.evaluate_expr(expr.operand)
        if expr.op == '!':
            return not self.is_truthy(operand)
        if expr.op == '-':
            return -operand
        raise EvaluationError(f"Unknown unary operator: {expr.op}")

    def evaluate_function(self, expr: FunctionCall) -> Any:
        args = [self.evaluate_expr(a) for a in expr.args]
        name = expr.name

        if name == 'len':
            self._check_arg_count(args, 1, 'len')
            return len(args[0])

        if name == 'contains':
            self._check_arg_count(args, 2, 'contains')
            text = self._resolve_text(args[0])
            try:
                if re.search(args[1], text):
                    return True
            except re.error:
                pass
            return args[1] in text

        if name == 'equals':
            self._check_arg_count(args, 2, 'equals')
            target, value = args
            if isinstance(value, int) and target in ('exit code', 'exit_code'):
                return self.exit_code == value
            return self._resolve_text(target) == str(value)

        if name == 'exists':
            self._check_arg_count(args, 1, 'exists')
            return os.path.exists(self._resolve_path(args[0]))

        if name == 'fail':
            return ('fail', args[0] if args else None)

        raise EvaluationError(f"Unknown function: {name}")

    @staticmethod
    def _check_arg_count(args: List[Any], expected: int, fn: str):
        if len(args) != expected:
            raise EvaluationError(f"{fn}() takes exactly {expected} arguments")

    def _resolve_text(self, target: Any) -> str:
        if target == 'stdout':
            return self.stdout
        if target == 'stderr':
            return self.stderr
        if target in ('exit code', 'exit_code'):
            return str(self.exit_code)
        if isinstance(target, str) and os.path.isfile(self._resolve_path(target)):
            with open(self._resolve_path(target), 'r') as f:
                return f.read()
        return str(target)

    def evaluate_template_string(self, expr: TemplateString) -> str:
        result = []
        for part in expr.parts:
            if isinstance(part, str):
                result.append(part)
            elif isinstance(part, ASTNode):
                value = self.evaluate_expr(part)
                if isinstance(value, list):
                    raise EvaluationError("Cannot convert list to string")
                result.append(str(value))
            else:
                result.append(str(part))
        return ''.join(result)

    def _resolve_path(self, path: str) -> str:
        if os.path.isabs(path):
            return path
        if self.output_dir:
            return os.path.join(self.output_dir, path)
        if self.workspace:
            return os.path.join(self.workspace, path)
        return path

    @staticmethod
    def is_truthy(value: Any) -> bool:
        if isinstance(value, (bool, int, float)):
            return bool(value)
        if isinstance(value, (str, list)):
            return len(value) > 0
        return bool(value)

    @staticmethod
    def default_for_type(type_name: str) -> Any:
        return {'string': '', 'int': 0, 'float': 0.0, 'bool': False}.get(type_name)

    def evaluate_success(self, success_block: Dict[str, List[ASTNode]]) -> Dict[str, bool]:
        results = {}
        for name, statements in success_block.items():
            try:
                self.evaluate_statements(statements)
                results[name] = True
            except ReturnValue as rv:
                results[name] = self.is_truthy(rv.value)
            except Exception:
                results[name] = False
        return results

"""Cache management for pipeline tasks."""

import hashlib
import json
import os
import shutil
import time
from dataclasses import dataclass
from typing import Any, Dict, List, Optional

from ast_nodes import CacheConfig


@dataclass
class CachedResult:
    """Cached task result."""
    stdout: str
    stderr: str
    exit_code: int
    success: Dict[str, bool]
    output_files: Dict[str, bytes]
    timestamp: float


class CacheManager:
    """Manages task result caching."""

    def __init__(self, cache_location: str):
        self.cache_location = cache_location

    def get_cache_path(self, cache_key: str) -> str:
        return os.path.join(self.cache_location, cache_key[:2], cache_key[2:4], cache_key + ".json")

    def get_data_path(self, cache_key: str) -> str:
        return os.path.join(self.cache_location, cache_key[:2], cache_key[2:4], cache_key + "_data")

    def compute_key(self, task_name: str, params: Dict[str, Any],
                    inputs: List[str], cache_config: CacheConfig) -> str:
        """Compute a cache key for the task."""
        hasher = hashlib.sha256()
        hasher.update(task_name.encode())

        if cache_config.key_include:
            filtered_params = {k: v for k, v in params.items() if k in cache_config.key_include}
        elif cache_config.key_exclude:
            filtered_params = {k: v for k, v in params.items() if k not in cache_config.key_exclude}
        else:
            filtered_params = params

        hasher.update(json.dumps(filtered_params, sort_keys=True).encode())

        if cache_config.strategy == "content":
            for input_path in sorted(inputs):
                self._hash_path(hasher, input_path)

        if cache_config.version:
            hasher.update(cache_config.version.encode())

        return hasher.hexdigest()

    def _hash_path(self, hasher: Any, path: str):
        """Hash a file or directory contents."""
        if os.path.isfile(path):
            with open(path, 'rb') as f:
                hasher.update(f.read())
        elif os.path.isdir(path):
            for root, dirs, files in os.walk(path):
                dirs.sort()
                for fname in sorted(files):
                    fpath = os.path.join(root, fname)
                    try:
                        with open(fpath, 'rb') as f:
                            hasher.update(fpath.encode())
                            hasher.update(f.read())
                    except (IOError, OSError):
                        pass

    def check(self, cache_key: str, cache_config: CacheConfig) -> Optional[CachedResult]:
        """Check if a valid cache entry exists."""
        cache_path = self.get_cache_path(cache_key)
        if not os.path.exists(cache_path):
            return None

        try:
            with open(cache_path, 'r') as f:
                data = json.load(f)

            cached = CachedResult(
                stdout=data['stdout'],
                stderr=data['stderr'],
                exit_code=data['exit_code'],
                success=data['success'],
                output_files={},
                timestamp=data['timestamp']
            )

            ttl_seconds = self._compute_ttl(cache_config)
            if ttl_seconds > 0 and time.time() - cached.timestamp > ttl_seconds:
                return None

            self._load_output_files(cache_key, cached)
            return cached
        except Exception:
            return None

    def _compute_ttl(self, cache_config: CacheConfig) -> int:
        """Compute total TTL in seconds."""
        ttl = 0
        if cache_config.ttl_seconds:
            ttl += cache_config.ttl_seconds
        if cache_config.ttl_minutes:
            ttl += cache_config.ttl_minutes * 60
        if cache_config.ttl_hours:
            ttl += cache_config.ttl_hours * 3600
        if cache_config.ttl_days:
            ttl += cache_config.ttl_days * 86400
        return ttl

    def _load_output_files(self, cache_key: str, cached: CachedResult):
        """Load cached output files."""
        data_path = self.get_data_path(cache_key)
        if os.path.exists(data_path):
            for fname in os.listdir(data_path):
                fpath = os.path.join(data_path, fname)
                if os.path.isfile(fpath):
                    with open(fpath, 'rb') as f:
                        cached.output_files[fname] = f.read()

    def save(self, cache_key: str, stdout: str, stderr: str, exit_code: int,
             success: Dict[str, bool], output_dir: Optional[str]):
        """Save task result to cache."""
        cache_path = self.get_cache_path(cache_key)
        data_path = self.get_data_path(cache_key)

        os.makedirs(os.path.dirname(cache_path), exist_ok=True)

        with open(cache_path, 'w') as f:
            json.dump({
                'stdout': stdout,
                'stderr': stderr,
                'exit_code': exit_code,
                'success': success,
                'timestamp': time.time()
            }, f)

        if output_dir and os.path.exists(output_dir):
            os.makedirs(data_path, exist_ok=True)
            for item in os.listdir(output_dir):
                src = os.path.join(output_dir, item)
                dst = os.path.join(data_path, item)
                if os.path.isfile(src):
                    shutil.copy2(src, dst)
                elif os.path.isdir(src):
                    if os.path.exists(dst):
                        shutil.rmtree(dst)
                    shutil.copytree(src, dst)

    def restore_files(self, cache_key: str, output_dir: Optional[str],
                      output_files: Dict[str, bytes]):
        """Restore cached output files."""
        if not output_dir or not output_files:
            return
        os.makedirs(output_dir, exist_ok=True)
        for fname, content in output_files.items():
            fpath = os.path.join(output_dir, fname)
            parent = os.path.dirname(fpath)
            if parent:
                os.makedirs(parent, exist_ok=True)
            with open(fpath, 'wb') as f:
                f.write(content)

"""
AST nodes for the pipeline parser.
"""

from dataclasses import dataclass, field
from typing import Any, Dict, List, Optional, Union


@dataclass
class ASTNode:
    pass


# Expression nodes
@dataclass
class Literal(ASTNode):
    value: Any


@dataclass
class Identifier(ASTNode):
    name: str


@dataclass
class BinaryOp(ASTNode):
    op: str
    left: ASTNode
    right: ASTNode


@dataclass
class UnaryOp(ASTNode):
    op: str
    operand: ASTNode


@dataclass
class ArrayAccess(ASTNode):
    array: ASTNode
    index: ASTNode


@dataclass
class FunctionCall(ASTNode):
    name: str
    args: List[ASTNode]
    kwargs: Dict[str, ASTNode] = field(default_factory=dict)


@dataclass
class TaskCall(ASTNode):
    name: str
    args: List[ASTNode]
    kwargs: Dict[str, ASTNode] = field(default_factory=dict)


@dataclass
class TemplateString(ASTNode):
    parts: List[Union[str, ASTNode]]


@dataclass
class ListLiteral(ASTNode):
    elements: List[ASTNode]


@dataclass
class ParameterAccess(ASTNode):
    param_name: str


@dataclass
class WorkspaceAccess(ASTNode):
    pass


# Statement nodes
@dataclass
class VarDecl(ASTNode):
    var_type: str
    var_name: str
    value: ASTNode
    is_list_element_type: bool = False


@dataclass
class Assignment(ASTNode):
    name: ASTNode
    value: ASTNode


@dataclass
class IfStatement(ASTNode):
    condition: ASTNode
    then_block: List[ASTNode]
    elif_clauses: List[tuple]  # List of (condition, block)
    else_block: Optional[List[ASTNode]]


@dataclass
class ForStatement(ASTNode):
    init: Optional[ASTNode]
    condition: Optional[ASTNode]
    update: Optional[ASTNode]
    body: List[ASTNode]
    is_foreach: bool = False
    var_name: str = ""
    iterable: ASTNode = None


@dataclass
class WhileStatement(ASTNode):
    condition: ASTNode
    body: List[ASTNode]


@dataclass
class ReturnStatement(ASTNode):
    value: Optional[ASTNode]


@dataclass
class BreakStatement(ASTNode):
    pass


@dataclass
class ContinueStatement(ASTNode):
    pass


@dataclass
class ExpressionStatement(ASTNode):
    expression: ASTNode


@dataclass
class FailsTask(ASTNode):
    task_call: TaskCall


# Parameter definition
@dataclass
class ParamDef(ASTNode):
    name: str
    param_type: str
    default_value: Optional[ASTNode]
    is_list_element_type: bool = False


# Cache configuration
@dataclass
class CacheConfig(ASTNode):
    enabled: bool = False
    strategy: str = "content"  # "content", "stale", "always"
    location: str = ".pipe-cache"
    version: Optional[str] = None
    ttl_seconds: Optional[int] = None
    ttl_minutes: Optional[int] = None
    ttl_hours: Optional[int] = None
    ttl_days: Optional[int] = None
    key_include: Optional[List[str]] = None
    key_exclude: Optional[List[str]] = None


# Task definition
@dataclass
class TaskDef(ASTNode):
    name: str
    params: List[ParamDef]
    inputs: Optional[List[str]]
    run: Optional[str]
    success: Dict[str, List[ASTNode]]
    requires: List[ASTNode]
    output: Optional[ASTNode]
    timeout: Optional[float]
    cache: Optional[CacheConfig] = None


# Pipeline
@dataclass
class Pipeline(ASTNode):
    tasks: Dict[str, TaskDef]

"""Pipeline executor - runs tasks and manages dependencies."""

import glob
import json
import os
import re
import shutil
import subprocess
import sys
import time
from dataclasses import dataclass, asdict, field
from typing import Any, Dict, List, Optional, Tuple, Set

try:
    import tomli
except ImportError:
    import toml as tomli

from parser import parse_pipeline
from ast_nodes import ASTNode, TaskCall, FailsTask, ExpressionStatement, TemplateString, Pipeline, CacheConfig
from evaluator import ExprEvaluator, EvaluationError, ReturnValue, BreakSignal, ContinueSignal
from cache import CacheManager, CachedResult


class PipelineError(Exception):
    """Base exception for pipeline errors."""
    def __init__(self, code: int, message: str):
        self.code = code
        self.message = message
        super().__init__(f"Exit {code}: {message}")


class SyntaxError_(PipelineError):
    def __init__(self, message: str):
        super().__init__(2, f"SYNTAX_ERROR:{message}")


class InvalidPipeError(PipelineError):
    def __init__(self, message: str):
        super().__init__(3, f"INVALID_PIPE:{message}")


@dataclass
class TaskResult:
    """Result of a task execution."""
    job_id: int
    task_name: str
    params: Dict[str, Any]
    stdout: str
    stderr: str
    timed_out: bool
    success: Dict[str, bool]
    output: Optional[str]
    exit_code: int
    parent: Optional[int]
    duration: float
    inputs: Optional[List[str]] = None
    cache: Optional[Dict[str, Any]] = None
    cache_hit: Optional[bool] = None
    cache_key: Optional[str] = None

    def to_dict(self) -> Dict[str, Any]:
        result = asdict(self)
        if self.cache is None:
            result.pop('cache_hit', None)
            result.pop('cache_key', None)
        return result


@dataclass
class PendingTaskCall:
    """Represents a pending task call."""
    name: str
    args: List[Any]
    kwargs: Dict[str, Any]
    parent: Optional[int]
    expect_fail: bool = False


@dataclass
class GlobalCacheConfig:
    """Global cache configuration from config file."""
    enabled: bool = True
    location: str = ".pipe-cache"
    force_refresh: List[str] = field(default_factory=list)


class PipelineExecutor:
    """Executes pipeline tasks with caching support."""

    BUILTIN_FUNCTIONS = frozenset(['len', 'contains', 'equals', 'exists', 'fail'])

    def __init__(self, pipeline_path: str, workspace: str, output_dir: str, config_path: Optional[str] = None):
        self.pipeline_path = pipeline_path
        self.workspace = os.path.abspath(workspace)
        self.output_dir = os.path.abspath(output_dir)
        self.config_path = config_path

        self.pipeline: Optional[Pipeline] = None
        self.config: Dict[str, Any] = {}
        self.env_vars: Dict[str, str] = {}
        self.entry_task: Optional[str] = None
        self.clean_cwd: bool = False
        self.global_cache_config = GlobalCacheConfig()

        self.job_counter = 0
        self.results: List[TaskResult] = []
        self.task_stack: Set[str] = set()
        self.run_cache: Dict[str, Tuple[int, TaskResult]] = {}

        self.jobs_file = None
        self.jobs_path = os.path.join(self.output_dir, "jobs.jsonl")

    def load_pipeline(self):
        """Load and parse the pipeline file."""
        try:
            with open(self.pipeline_path, 'r') as f:
                source = f.read()
            self.pipeline = parse_pipeline(source)
        except FileNotFoundError:
            raise InvalidPipeError(f"Pipeline file not found: {self.pipeline_path}")
        except Exception as e:
            raise SyntaxError_(str(e))

    def load_config(self):
        """Load the config file if specified."""
        if not self.config_path:
            return

        try:
            with open(self.config_path, 'rb') as f:
                self.config = tomli.load(f)
        except FileNotFoundError:
            raise InvalidPipeError(f"Config file not found: {self.config_path}")
        except Exception as e:
            raise SyntaxError_(f"Invalid TOML: {e}")

        self.env_vars = {k: str(v) for k, v in self.config.get('env', {}).items()}
        self.entry_task = self.config.get('entry', 'main')
        self.clean_cwd = self.config.get('clean_cwd', False)

        if 'cache' in self.config:
            cache_cfg = self.config['cache']
            self.global_cache_config.enabled = cache_cfg.get('enabled', True)
            if 'location' in cache_cfg:
                self.global_cache_config.location = cache_cfg['location']
            if 'force_refresh' in cache_cfg:
                self.global_cache_config.force_refresh = cache_cfg['force_refresh']

    def emit_event(self, event: str, job_id: int, **kwargs):
        """Emit a JSON event to stdout."""
        data = {"event": event, "job_id": job_id}
        data.update(kwargs)
        print(json.dumps(data), flush=True)

    def write_job_result(self, result: TaskResult):
        """Write a job result to the jobs.jsonl file."""
        if self.jobs_file is None:
            os.makedirs(self.output_dir, exist_ok=True)
            self.jobs_file = open(self.jobs_path, 'w')
        self.jobs_file.write(json.dumps(result.to_dict()) + '\n')
        self.jobs_file.flush()

    def resolve_params(self, task, call: PendingTaskCall) -> Dict[str, Any]:
        """Resolve parameters for a task call."""
        params = {}
        param_defs = {p.name: p for p in task.params}

        args = list(call.args)
        for i, param in enumerate(task.params):
            if i < len(args):
                params[param.name] = self._cast_value(args[i], param.param_type, param.is_list_element_type)
            elif param.name in call.kwargs:
                params[param.name] = self._cast_value(call.kwargs[param.name], param.param_type, param.is_list_element_type)
            elif param.default_value is not None:
                params[param.name] = self._evaluate_default(param.default_value, param.param_type, param.is_list_element_type)
            else:
                raise InvalidPipeError(f"Missing required parameter '{param.name}' for task '{task.name}'")

        for name, value in call.kwargs.items():
            if name not in param_defs:
                raise InvalidPipeError(f"Unknown parameter '{name}' for task '{task.name}'")
            params[name] = self._cast_value(value, param_defs[name].param_type, param_defs[name].is_list_element_type)

        return params

    def _cast_value(self, value: Any, type_name: str, is_list: bool) -> Any:
        if is_list:
            if not isinstance(value, list):
                raise InvalidPipeError(f"Expected list, got {type(value).__name__}")
            return [self._cast_single(v, type_name) for v in value]
        return self._cast_single(value, type_name)

    def _cast_single(self, value: Any, type_name: str) -> Any:
        if isinstance(value, bool) and type_name == 'bool':
            return value
        if isinstance(value, int) and type_name in ('int', 'float'):
            return float(value) if type_name == 'float' else value
        if isinstance(value, float) and type_name in ('int', 'float'):
            return int(value) if type_name == 'int' else value
        if isinstance(value, str):
            if type_name == 'string':
                return value
            try:
                if type_name == 'int':
                    return int(value)
                if type_name == 'float':
                    return float(value)
            except ValueError:
                raise InvalidPipeError(f"Cannot convert '{value}' to {type_name}")
            if type_name == 'bool':
                if value.lower() in ('true', '1', 'yes'):
                    return True
                if value.lower() in ('false', '0', 'no', ''):
                    return False
                raise InvalidPipeError(f"Cannot convert '{value}' to bool")
        return value

    def _evaluate_default(self, default: ASTNode, type_name: str, is_list: bool) -> Any:
        evaluator = ExprEvaluator(env_vars=self.env_vars, workspace=self.workspace)
        value = evaluator.evaluate_expr(default)

        if isinstance(default, TemplateString):
            for part in default.parts:
                if isinstance(part, str) and part.startswith('${') and part.endswith('}'):
                    var_name = part[2:-1]
                    if var_name in self.env_vars:
                        value = self._cast_single(self.env_vars[var_name], type_name)

        return self._cast_value(value, type_name, is_list)

    def resolve_run_command(self, run: str, params: Dict[str, Any], output_dir: Optional[str]) -> str:
        result = run
        for name, value in params.items():
            value_str = ' '.join(str(v) for v in value) if isinstance(value, list) else str(value)
            result = result.replace(f'${{params.{name}}}', value_str)
        result = result.replace('${workspace}', self.workspace)
        if output_dir:
            result = result.replace('${output}', output_dir)
        return result

    def resolve_output_path(self, output_expr: Optional[ASTNode], params: Dict[str, Any]) -> Optional[str]:
        if output_expr is None:
            return None

        evaluator = ExprEvaluator(
            variables={'params': params},
            env_vars=self.env_vars,
            workspace=self.workspace
        )
        result = evaluator.evaluate_expr(output_expr)

        if isinstance(result, str):
            result = result.replace('${workspace}', self.workspace)
            if not os.path.isabs(result):
                full_path = os.path.join(self.workspace, result)
            else:
                full_path = result
            if not os.path.abspath(full_path).startswith(self.workspace):
                raise InvalidPipeError(f"Output path escapes workspace: {result}")
            return result
        return None

    def execute_run(self, command: str, cwd: str, timeout: Optional[float]) -> Tuple[str, str, int, bool]:
        command = command.replace('\u2018', "'").replace('\u2019', "'")
        try:
            result = subprocess.run(
                ['bash', '-c', command],
                capture_output=True,
                text=True,
                cwd=cwd,
                timeout=timeout
            )
            return result.stdout, result.stderr, result.returncode, False
        except subprocess.TimeoutExpired:
            return "", "", 124, True
        except Exception as e:
            return "", str(e), 1, False

    def check_circular_dependency(self, task_name: str):
        if task_name in self.task_stack:
            raise InvalidPipeError(f"Circular dependency detected: {task_name}")
        self.task_stack.add(task_name)

    def resolve_inputs(self, inputs: Optional[List[str]], params: Dict[str, Any]) -> List[str]:
        if not inputs:
            return []

        resolved = []
        for pattern in inputs:
            for name, value in params.items():
                pattern = pattern.replace(f'${{params.{name}}}', str(value))
            pattern = pattern.replace('${workspace}', self.workspace)

            if '*' in pattern or '?' in pattern:
                resolved.extend(sorted(glob.glob(pattern, recursive=True)))
            else:
                resolved.append(pattern)
        return resolved

    def _is_cacheable(self, task_name: str, task) -> bool:
        if not task.cache or not task.cache.enabled:
            return False
        if not self.global_cache_config.enabled:
            return False
        if task_name in self.global_cache_config.force_refresh:
            return False
        return True

    def _get_cache_manager(self, cache_config: CacheConfig) -> CacheManager:
        location = cache_config.location
        if not os.path.isabs(location):
            location = os.path.join(self.workspace, location)
        return CacheManager(location)

    def _make_cache_config_dict(self, cache_config: CacheConfig) -> Dict[str, Any]:
        result = {
            'enabled': cache_config.enabled,
            'strategy': cache_config.strategy,
            'location': cache_config.location
        }
        if cache_config.version:
            result['version'] = cache_config.version
        return result

    def execute_task(self, call: PendingTaskCall) -> TaskResult:
        self.job_counter += 1
        job_id = self.job_counter

        if call.name not in self.pipeline.tasks:
            raise InvalidPipeError(f"Undefined task: {call.name}")

        task = self.pipeline.tasks[call.name]
        self.check_circular_dependency(call.name)
        self.emit_event("TASK_STARTED", job_id, task=call.name, params=call.kwargs if call.kwargs else call.args)

        params = self.resolve_params(task, call)
        output_dir = self._prepare_output_dir(task.output, params)
        work_dir = output_dir if output_dir else self.workspace
        resolved_inputs = self.resolve_inputs(task.inputs, params)

        cache_hit = False
        cache_key = None
        cache_config_dict = None
        cache_manager = None

        if self._is_cacheable(call.name, task):
            cache_manager = self._get_cache_manager(task.cache)
            cache_key = cache_manager.compute_key(call.name, params, resolved_inputs, task.cache)
            cache_config_dict = self._make_cache_config_dict(task.cache)
            self.emit_event("CACHE_CHECK", job_id, cache_key=cache_key, task=call.name)

            result = self._try_cache(job_id, call, params, output_dir, resolved_inputs,
                                     cache_config_dict, cache_key, cache_manager, task.cache)
            if result:
                return result

        stdout, stderr, exit_code, timed_out, duration, success = self._execute_task_body(
            task, params, output_dir, work_dir, job_id, resolved_inputs
        )

        task_success = exit_code == 0 and all(success.values()) if success else exit_code == 0
        self.emit_event("TASK_COMPLETED" if task_success else "TASK_FAILED", job_id)
        self.task_stack.discard(call.name)

        result = TaskResult(
            job_id=job_id, task_name=call.name, params=params, stdout=stdout, stderr=stderr,
            timed_out=timed_out, success=success, output=output_dir, exit_code=exit_code,
            parent=call.parent, duration=round(duration, 4), inputs=resolved_inputs or None,
            cache=cache_config_dict, cache_hit=cache_hit, cache_key=cache_key
        )

        if cache_manager and cache_key and task_success:
            cache_manager.save(cache_key, stdout, stderr, exit_code, success, output_dir)
            self.run_cache[cache_key] = (job_id, result)

        self.results.append(result)
        self.write_job_result(result)
        return result

    def _prepare_output_dir(self, output_expr: Optional[ASTNode], params: Dict[str, Any]) -> Optional[str]:
        output_dir = self.resolve_output_path(output_expr, params)
        if output_dir:
            if not os.path.isabs(output_dir):
                output_dir = os.path.join(self.workspace, output_dir)
            os.makedirs(output_dir, exist_ok=True)
        return output_dir

    def _try_cache(self, job_id: int, call: PendingTaskCall, params: Dict[str, Any],
                   output_dir: Optional[str], resolved_inputs: List[str],
                   cache_config_dict: Dict[str, Any], cache_key: str,
                   cache_manager: CacheManager, cache_config: CacheConfig) -> Optional[TaskResult]:
        if cache_key in self.run_cache:
            cached_job_id, cached_result = self.run_cache[cache_key]
            self.emit_event("CACHE_HIT", job_id, cache_key=cache_key, task=call.name, cached_job_id=cached_job_id)
            result = TaskResult(
                job_id=job_id, task_name=call.name, params=params, stdout=cached_result.stdout,
                stderr=cached_result.stderr, timed_out=False, success=cached_result.success,
                output=output_dir, exit_code=cached_result.exit_code, parent=call.parent,
                duration=0.0, inputs=resolved_inputs or None, cache=cache_config_dict,
                cache_hit=True, cache_key=cache_key
            )
            self._finalize_task(result, call.name)
            return result

        cached = cache_manager.check(cache_key, cache_config)
        if cached:
            self.emit_event("CACHE_HIT", job_id, cache_key=cache_key, task=call.name)
            cache_manager.restore_files(cache_key, output_dir, cached.output_files)
            result = TaskResult(
                job_id=job_id, task_name=call.name, params=params, stdout=cached.stdout,
                stderr=cached.stderr, timed_out=False, success=cached.success, output=output_dir,
                exit_code=cached.exit_code, parent=call.parent, duration=0.0,
                inputs=resolved_inputs or None, cache=cache_config_dict, cache_hit=True, cache_key=cache_key
            )
            self.run_cache[cache_key] = (job_id, result)
            self._finalize_task(result, call.name)
            return result

        self.emit_event("CACHE_MISS", job_id, cache_key=cache_key, task=call.name)
        return None

    def _finalize_task(self, result: TaskResult, task_name: str):
        self.emit_event("TASK_COMPLETED", result.job_id)
        self.task_stack.discard(task_name)
        self.results.append(result)
        self.write_job_result(result)

    def _execute_task_body(self, task, params: Dict[str, Any], output_dir: Optional[str],
                           work_dir: str, job_id: int, resolved_inputs: List[str]
                           ) -> Tuple[str, str, int, bool, float, Dict[str, bool]]:
        if task.requires:
            if not self._execute_requires(task.requires, params, job_id, output_dir):
                return "", "", 1, False, 0.0, {}

        stdout, stderr, exit_code, timed_out, duration = "", "", 0, False, 0.0

        if task.run:
            self.emit_event("TASK_RUNNING", job_id)
            start_time = time.time()
            command = self.resolve_run_command(task.run, params, output_dir)
            stdout, stderr, exit_code, timed_out = self.execute_run(command, work_dir, task.timeout)
            duration = time.time() - start_time
            stdout = stdout.replace('\u2018', "'").replace('\u2019', "'")
            stderr = stderr.replace('\u2018', "'").replace('\u2019', "'")

        success = self._evaluate_success(task.success, params, stdout, stderr, exit_code, output_dir)
        return stdout, stderr, exit_code, timed_out, duration, success

    def _evaluate_success(self, success_block: Optional[Dict[str, List[ASTNode]]],
                          params: Dict[str, Any], stdout: str, stderr: str,
                          exit_code: int, output_dir: Optional[str]) -> Dict[str, bool]:
        if not success_block:
            return {}

        evaluator = ExprEvaluator(
            variables={'params': params}, env_vars=self.env_vars, stdout=stdout,
            stderr=stderr, exit_code=exit_code, output_dir=output_dir, workspace=self.workspace
        )
        try:
            return evaluator.evaluate_success(success_block)
        except Exception:
            return {name: False for name in success_block}

    def _execute_requires(self, statements: List[ASTNode], params: Dict[str, Any],
                          parent_id: int, output_dir: Optional[str]) -> bool:
        evaluator = RequiresEvaluator(self, params, parent_id, output_dir)
        try:
            evaluator.evaluate_statements(statements)
            return True
        except Exception as e:
            return not isinstance(e, (ReturnValue, BreakSignal, ContinueSignal))

    def run(self) -> int:
        try:
            self.load_pipeline()
            self.load_config()

            os.makedirs(self.workspace, exist_ok=True)
            os.makedirs(self.output_dir, exist_ok=True)

            if self.clean_cwd:
                for item in os.listdir(self.workspace):
                    path = os.path.join(self.workspace, item)
                    if os.path.isfile(path):
                        os.remove(path)
                    elif os.path.isdir(path):
                        shutil.rmtree(path)

            entry = self.entry_task or 'main'
            entry_call = self._parse_entry_call(entry, parent=None)
            result = self.execute_task(entry_call)

            if self.jobs_file:
                self.jobs_file.close()

            return 0 if result.exit_code == 0 else 1

        except PipelineError as e:
            print(e.message, file=sys.stderr)
            return e.code
        except Exception as e:
            print(f"SYNTAX_ERROR:{str(e)}", file=sys.stderr)
            return 2

    def _parse_entry_call(self, entry: str, parent: Optional[int]) -> PendingTaskCall:
        entry = entry.strip()
        if '(' not in entry:
            return PendingTaskCall(name=entry, args=[], kwargs={}, parent=parent)

        match = re.match(r'(\w+)\((.*)\)', entry)
        if not match:
            raise InvalidPipeError(f"Invalid entry task specification: {entry}")

        name = match.group(1)
        args_str = match.group(2).strip()

        if not args_str:
            return PendingTaskCall(name=name, args=[], kwargs={}, parent=parent)

        args, kwargs = [], {}
        for part in self._split_args(args_str):
            part = part.strip()
            if '=' in part:
                key, value = part.split('=', 1)
                kwargs[key.strip()] = self._parse_value(value.strip())
            else:
                args.append(self._parse_value(part))

        return PendingTaskCall(name=name, args=args, kwargs=kwargs, parent=parent)

    def _split_args(self, args_str: str) -> List[str]:
        result, current, depth, in_string, string_char = [], [], 0, False, None

        for char in args_str:
            if char in ('"', "'") and not in_string:
                in_string, string_char = True, char
            elif char == string_char and in_string:
                in_string = False
            elif char == '(' and not in_string:
                depth += 1
            elif char == ')' and not in_string:
                depth -= 1
            elif char == ',' and depth == 0 and not in_string:
                result.append(''.join(current))
                current = []
                continue
            current.append(char)

        if current:
            result.append(''.join(current))
        return result

    def _parse_value(self, value: str) -> Any:
        value = value.strip()
        if value == 'TRUE':
            return True
        if value == 'FALSE':
            return False
        if (value.startswith('"') and value.endswith('"')) or (value.startswith("'") and value.endswith("'")):
            return value[1:-1]
        try:
            return int(value)
        except ValueError:
            pass
        try:
            return float(value)
        except ValueError:
            pass
        return value


class RequiresEvaluator(ExprEvaluator):
    """Evaluator for requires blocks that handles task calls."""

    def __init__(self, executor: PipelineExecutor, params: Dict[str, Any],
                 parent_id: int, output_dir: Optional[str]):
        super().__init__(
            variables={'params': params},
            env_vars=executor.env_vars,
            workspace=executor.workspace
        )
        self.executor = executor
        self.parent_id = parent_id

    def evaluate_statement(self, stmt: ASTNode) -> Any:
        if isinstance(stmt, FailsTask):
            return self._run_task(stmt.task_call, expect_fail=True)
        if isinstance(stmt, ExpressionStatement):
            stmt = stmt.expression
        if isinstance(stmt, TaskCall):
            return self._run_task(stmt, expect_fail=False)
        return super().evaluate_statement(stmt)

    def evaluate_expr(self, expr: ASTNode) -> Any:
        if isinstance(expr, TaskCall):
            return self._run_task(expr, expect_fail=False)
        if isinstance(expr, FailsTask):
            return self._run_task(expr.task_call, expect_fail=True)
        return super().evaluate_expr(expr)

    def _run_task(self, call: TaskCall, expect_fail: bool) -> bool:
        args = [self.evaluate_expr(a) if isinstance(a, ASTNode) else a for a in call.args]
        kwargs = {k: self.evaluate_expr(v) if isinstance(v, ASTNode) else v for k, v in call.kwargs.items()}

        pending = PendingTaskCall(name=call.name, args=args, kwargs=kwargs, parent=self.parent_id, expect_fail=expect_fail)
        result = self.executor.execute_task(pending)

        if expect_fail:
            if result.exit_code == 0:
                raise EvaluationError(f"Task {call.name} was expected to fail but succeeded")
            return True
        if result.exit_code != 0:
            raise EvaluationError(f"Task {call.name} failed")
        return True

"""Pipeline file parser with run block preprocessing."""

import re
from typing import Dict, List, Optional, Tuple

from lexer import Token, TokenType, Lexer
from ast_nodes import (
    ASTNode, Literal, Identifier, BinaryOp, UnaryOp, ArrayAccess,
    FunctionCall, TaskCall, TemplateString, ListLiteral,
    ParameterAccess, WorkspaceAccess, VarDecl, IfStatement, ForStatement,
    WhileStatement, ReturnStatement, BreakStatement, ContinueStatement,
    ExpressionStatement, FailsTask, ParamDef, TaskDef, Pipeline, CacheConfig,
)


class ParseError(Exception):
    def __init__(self, message: str, line: int = None, column: int = None):
        self.message = message
        self.line = line
        self.column = column
        super().__init__(f"SYNTAX_ERROR: {message}")


class Parser:
    def __init__(self, tokens: List[Token], run_blocks: Dict[str, str] = None):
        self.tokens = tokens
        self.pos = 0
        self.run_blocks = run_blocks or {}

    def error(self, message: str) -> ParseError:
        token = self.current()
        return ParseError(message, token.line, token.column)

    def current(self) -> Token:
        if self.pos < len(self.tokens):
            return self.tokens[self.pos]
        return self.tokens[-1]

    def peek(self, offset: int = 0) -> Token:
        pos = self.pos + offset
        if pos < len(self.tokens):
            return self.tokens[pos]
        return self.tokens[-1]

    def advance(self) -> Token:
        token = self.current()
        self.pos += 1
        return token

    def match(self, *types: TokenType) -> bool:
        return self.current().type in types

    def expect(self, token_type: TokenType, message: str = None) -> Token:
        if self.current().type != token_type:
            msg = message or f"Expected {token_type.name}, got {self.current().type.name}"
            raise self.error(msg)
        return self.advance()

    def skip_newlines(self):
        while self.match(TokenType.NEWLINE):
            self.advance()

    def _skip_optional_colon(self):
        if self.match(TokenType.COLON):
            self.advance()

    def _skip_optional_semicolon(self):
        if self.match(TokenType.SEMICOLON):
            self.advance()

    def parse(self) -> Pipeline:
        tasks = {}
        self.skip_newlines()

        while not self.match(TokenType.EOF):
            if self.match(TokenType.TASK):
                task = self.parse_task()
                tasks[task.name] = task
            else:
                raise self.error(f"Expected task definition, got {self.current().type.name}")
            self.skip_newlines()

        return Pipeline(tasks=tasks)

    def parse_task(self) -> TaskDef:
        self.expect(TokenType.TASK)
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        params, inputs, run, success, requires, output, timeout, cache = \
            [], None, None, {}, [], None, None, None

        while not self.match(TokenType.RBRACE, TokenType.EOF):
            if self.match(TokenType.PARAMS):
                params = self.parse_params()
            elif self.match(TokenType.INPUTS):
                inputs = self.parse_inputs()
            elif self.match(TokenType.RUN):
                run = self.parse_run()
            elif self.match(TokenType.SUCCESS):
                success = self.parse_success()
            elif self.match(TokenType.REQUIRES):
                requires = self.parse_requires()
            elif self.match(TokenType.OUTPUT):
                output = self.parse_output()
            elif self.match(TokenType.TIMEOUT):
                timeout = self.parse_timeout()
            elif self.match(TokenType.CACHE):
                cache = self.parse_cache()
            else:
                raise self.error(f"Unexpected token in task: {self.current().type.name}")
            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return TaskDef(name=name, params=params, inputs=inputs, run=run,
                       success=success, requires=requires, output=output,
                       timeout=timeout, cache=cache)

    def parse_params(self) -> List[ParamDef]:
        self.expect(TokenType.PARAMS)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        params = []
        has_default = False

        while not self.match(TokenType.RBRACE, TokenType.EOF):
            param = self.parse_param_def()
            if param.default_value is not None:
                has_default = True
            elif has_default:
                raise self.error(f"Parameter '{param.name}' without default cannot follow one with default")
            params.append(param)
            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return params

    def parse_param_def(self) -> ParamDef:
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.COLON)

        param_type, is_list = self.parse_type()
        default_value = None
        if self.match(TokenType.ASSIGN):
            self.advance()
            default_value = self.parse_literal_or_env()

        self._skip_optional_semicolon()
        return ParamDef(name=name, param_type=param_type, default_value=default_value, is_list_element_type=is_list)

    def parse_type(self) -> Tuple[str, bool]:
        type_map = {
            TokenType.STRING_TYPE: 'string',
            TokenType.INT_TYPE: 'int',
            TokenType.FLOAT_TYPE: 'float',
            TokenType.BOOL_TYPE: 'bool',
            TokenType.LIST_TYPE: 'list',
        }

        if self.current().type not in type_map:
            raise self.error(f"Expected type, got {self.current().type.name}")

        token = self.advance()
        param_type = type_map[token.type]

        if param_type == 'list' and self.match(TokenType.LBRACKET):
            self.advance()
            inner_type, _ = self.parse_type()
            self.expect(TokenType.RBRACKET)
            return inner_type, True

        return param_type, False

    def parse_literal_or_env(self) -> ASTNode:
        if self.match(TokenType.STRING):
            return Literal(self.advance().value)
        if self.match(TokenType.INT):
            return Literal(self.advance().value)
        if self.match(TokenType.FLOAT):
            return Literal(self.advance().value)
        if self.match(TokenType.TRUE):
            self.advance()
            return Literal(True)
        if self.match(TokenType.FALSE):
            self.advance()
            return Literal(False)
        if self.match(TokenType.LBRACKET):
            return self.parse_list_literal()
        if self.match(TokenType.DOLLAR):
            return self._parse_env_ref()
        raise self.error(f"Expected literal value, got {self.current().type.name}")

    def _parse_env_ref(self) -> TemplateString:
        """Parse ${...} environment variable reference."""
        self.advance()  # $
        if self.match(TokenType.LBRACE):
            self.advance()
            parts = []
            while not self.match(TokenType.RBRACE):
                if self.match(TokenType.IDENTIFIER):
                    parts.append(self.advance().value)
                elif self.match(TokenType.DOT):
                    self.advance()
                    parts.append('.')
                else:
                    raise self.error(f"Unexpected token in env var: {self.current().type.name}")
            self.expect(TokenType.RBRACE)
            return TemplateString(['${' + ''.join(parts) + '}'])
        if self.match(TokenType.IDENTIFIER):
            name = self.advance().value
            return TemplateString(['${' + name + '}'])
        raise self.error("Expected identifier after $")

    def parse_list_literal(self) -> ListLiteral:
        self.expect(TokenType.LBRACKET)
        elements = []
        while not self.match(TokenType.RBRACE, TokenType.EOF):
            elements.append(self.parse_literal_or_env())
            if self.match(TokenType.COMMA):
                self.advance()
        self.expect(TokenType.RBRACKET)
        return ListLiteral(elements)

    def parse_run(self) -> str:
        self.expect(TokenType.RUN)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACE)

        if self.match(TokenType.IDENTIFIER) and self.current().value.startswith('__RUN_BLOCK_'):
            placeholder = self.advance().value
            self.expect(TokenType.RBRACE)
            return self.run_blocks.get(placeholder, '')

        depth = 1
        content = []
        token_renderers = {
            TokenType.LBRACE: lambda t: '{',
            TokenType.RBRACE: lambda t: '}' if depth > 0 else '',
            TokenType.NEWLINE: lambda t: '\n',
            TokenType.DOLLAR: lambda t: '$',
            TokenType.COMMENT: lambda t: f'//{t.value}',
        }

        while depth > 0 and not self.match(TokenType.EOF):
            token = self.advance()
            if token.type == TokenType.LBRACE:
                depth += 1
                content.append('{')
            elif token.type == TokenType.RBRACE:
                depth -= 1
                if depth > 0:
                    content.append('}')
            elif token.type == TokenType.NEWLINE:
                content.append('\n')
            elif token.type == TokenType.STRING:
                content.append(f'"{token.value.replace(chr(34), chr(92) + chr(34))}"')
            elif token.type == TokenType.COMMENT:
                content.append(f'//{token.value}')
            else:
                content.append(str(token.value) if token.value else '')

        return ''.join(content).strip()

    def parse_success(self) -> Dict[str, List[ASTNode]]:
        self.expect(TokenType.SUCCESS)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        success = {}
        while not self.match(TokenType.RBRACE, TokenType.EOF):
            name = self.expect(TokenType.IDENTIFIER).value
            self.expect(TokenType.COLON)

            if self.match(TokenType.LBRACE):
                self.advance()
                self.skip_newlines()
                statements = self.parse_block_statements()
                self.expect(TokenType.RBRACE)
                success[name] = statements
            else:
                expr = self.parse_expression()
                self._skip_optional_semicolon()
                success[name] = [ReturnStatement(value=expr)]

            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return success

    def parse_requires(self) -> List[ASTNode]:
        self.expect(TokenType.REQUIRES)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        statements = self.parse_block_statements()
        self.expect(TokenType.RBRACE)
        return statements

    def parse_output(self) -> ASTNode:
        self.expect(TokenType.OUTPUT)
        self._skip_optional_colon()
        return self.parse_expression()

    def parse_timeout(self) -> float:
        self.expect(TokenType.TIMEOUT)
        self._skip_optional_colon()
        if self.match(TokenType.FLOAT):
            return self.advance().value
        if self.match(TokenType.INT):
            return float(self.advance().value)
        raise self.error("Expected number for timeout")

    def parse_inputs(self) -> List[str]:
        self.expect(TokenType.INPUTS)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACKET)
        self.skip_newlines()

        inputs = []
        while not self.match(TokenType.RBRACKET, TokenType.EOF):
            if self.match(TokenType.STRING):
                inputs.append(self.advance().value)
            elif self.match(TokenType.IDENTIFIER):
                parts = [self.advance().value]
                while self.match(TokenType.DOT, TokenType.SLASH, TokenType.IDENTIFIER):
                    parts.append(str(self.advance().value))
                inputs.append(''.join(parts))
            elif self.match(TokenType.DOLLAR):
                self.advance()
                if self.match(TokenType.LBRACE):
                    self.advance()
                    parts = ['${']
                    while not self.match(TokenType.RBRACE):
                        parts.append(str(self.advance().value))
                    self.expect(TokenType.RBRACE)
                    parts.append('}')
                    inputs.append(''.join(parts))
            else:
                raise self.error(f"Expected input file path, got {self.current().type.name}")
            if self.match(TokenType.COMMA):
                self.advance()
            self.skip_newlines()

        self.expect(TokenType.RBRACKET)
        return inputs

    def parse_cache(self) -> CacheConfig:
        self.expect(TokenType.CACHE)
        self._skip_optional_colon()
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        config = CacheConfig()

        while not self.match(TokenType.RBRACE, TokenType.EOF):
            key_token = self.current()

            if key_token.type == TokenType.ENABLED:
                self.advance()
                self._skip_optional_colon()
                config.enabled = self._parse_bool_value()
            elif key_token.type == TokenType.STRATEGY:
                self.advance()
                self._skip_optional_colon()
                config.strategy = self._parse_string_or_ident()
            elif key_token.type == TokenType.LOCATION:
                self.advance()
                self._skip_optional_colon()
                config.location = self._parse_string_or_ident()
            elif key_token.type == TokenType.VERSION:
                self.advance()
                self._skip_optional_colon()
                config.version = self._parse_version_value()
            elif key_token.type == TokenType.TTL:
                self.advance()
                self._skip_optional_colon()
                self._parse_ttl_block(config)
            elif key_token.type == TokenType.KEY:
                self.advance()
                self._skip_optional_colon()
                self._parse_key_block(config)
            else:
                raise self.error(f"Unexpected cache config key: {key_token.type.name}")

            self._skip_optional_semicolon()
            self.skip_newlines()

        self.expect(TokenType.RBRACE)
        return config

    def _parse_bool_value(self) -> bool:
        if self.match(TokenType.TRUE):
            self.advance()
            return True
        if self.match(TokenType.FALSE):
            self.advance()
            return False
        raise self.error("Expected TRUE or FALSE")

    def _parse_string_or_ident(self) -> str:
        if self.match(TokenType.STRING):
            return self.advance().value
        if self.match(TokenType.IDENTIFIER):
            return self.advance().value
        raise self.error("Expected string value")

    def _parse_version_value(self) -> str:
        if self.match(TokenType.STRING):
            return self.advance().value
        if self.match(TokenType.IDENTIFIER):
            return self.advance().value
        if self.match(TokenType.INT):
            return str(self.advance().value)
        raise self.error("Expected value for version")

    def _parse_ttl_block(self, config: CacheConfig):
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        ttl_fields = {
            TokenType.SECONDS: 'ttl_seconds',
            TokenType.MINUTES: 'ttl_minutes',
            TokenType.HOURS: 'ttl_hours',
            TokenType.DAYS: 'ttl_days',
        }

        while not self.match(TokenType.RBRACE, TokenType.EOF):
            key = self.current()
            if key.type in ttl_fields:
                self.advance()
                self._skip_optional_colon()
                setattr(config, ttl_fields[key.type], self.advance().value)
            else:
                raise self.error(f"Unexpected TTL key: {self.current().type.name}")
            self.skip_newlines()

        self.expect(TokenType.RBRACE)

    def _parse_key_block(self, config: CacheConfig):
        self.expect(TokenType.LBRACE)
        self.skip_newlines()

        while not self.match(TokenType.RBRACE, TokenType.EOF):
            key_inner = self.current()
            if key_inner.type == TokenType.INCLUDE:
                self.advance()
                self._skip_optional_colon()
                config.key_include = self._parse_string_list()
            elif key_inner.type == TokenType.EXCLUDE:
                self.advance()
                self._skip_optional_colon()
                config.key_exclude = self._parse_string_list()
            else:
                raise self.error(f"Unexpected key config: {self.current().type.name}")
            self.skip_newlines()

        self.expect(TokenType.RBRACE)

    def _parse_string_list(self) -> List[str]:
        self.expect(TokenType.LBRACKET)
        items = []
        while not self.match(TokenType.RBRACKET, TokenType.EOF):
            if self.match(TokenType.STRING):
                items.append(self.advance().value)
            elif self.match(TokenType.IDENTIFIER):
                items.append(self.advance().value)
            else:
                raise self.error(f"Expected string, got {self.current().type.name}")
            if self.match(TokenType.COMMA):
                self.advance()
        self.expect(TokenType.RBRACKET)
        return items

    def parse_block_statements(self) -> List[ASTNode]:
        statements = []
        while not self.match(TokenType.RBRACE, TokenType.EOF):
            stmt = self.parse_statement()
            if stmt is not None:
                statements.append(stmt)
            self.skip_newlines()
        return statements

    def parse_statement(self) -> Optional[ASTNode]:
        if self.match(TokenType.STRING_TYPE, TokenType.INT_TYPE, TokenType.FLOAT_TYPE,
                      TokenType.BOOL_TYPE, TokenType.LIST_TYPE):
            return self.parse_var_decl()
        if self.match(TokenType.IF):
            return self.parse_if()
        if self.match(TokenType.FOR):
            return self.parse_for()
        if self.match(TokenType.WHILE):
            return self.parse_while()
        if self.match(TokenType.RETURN):
            return self.parse_return()
        if self.match(TokenType.BREAK):
            self.advance()
            self._skip_optional_semicolon()
            return BreakStatement()
        if self.match(TokenType.CONTINUE):
            self.advance()
            self._skip_optional_semicolon()
            return ContinueStatement()
        if self.match(TokenType.FAILS):
            return self.parse_fails()
        if self.match(TokenType.IDENTIFIER, TokenType.NOT, TokenType.LPAREN):
            expr = self.parse_expression()
            self._skip_optional_semicolon()
            return ExpressionStatement(expr)
        return None

    def parse_var_decl(self) -> VarDecl:
        var_type, is_list = self.parse_type()
        name = self.expect(TokenType.IDENTIFIER).value
        value = None
        if self.match(TokenType.ASSIGN):
            self.advance()
            value = self.parse_expression()
        self._skip_optional_semicolon()
        return VarDecl(var_type=var_type, var_name=name, value=value, is_list_element_type=is_list)

    def parse_if(self) -> IfStatement:
        self.expect(TokenType.IF)
        self.expect(TokenType.LPAREN)
        condition = self.parse_expression()
        self.expect(TokenType.RPAREN)
        then_block = self._parse_brace_block()
        self.skip_newlines()

        elif_clauses = []
        while self.match(TokenType.ELIF):
            self.advance()
            self.expect(TokenType.LPAREN)
            elif_cond = self.parse_expression()
            self.expect(TokenType.RPAREN)
            elif_block = self._parse_brace_block()
            self.skip_newlines()
            elif_clauses.append((elif_cond, elif_block))

        else_block = None
        if self.match(TokenType.ELSE):
            self.advance()
            else_block = self._parse_brace_block()
            self.skip_newlines()

        return IfStatement(condition=condition, then_block=then_block,
                           elif_clauses=elif_clauses, else_block=else_block)

    def _parse_brace_block(self) -> List[ASTNode]:
        self.expect(TokenType.LBRACE)
        self.skip_newlines()
        stmts = self.parse_block_statements()
        self.expect(TokenType.RBRACE)
        return stmts

    def parse_for(self) -> ForStatement:
        self.expect(TokenType.FOR)
        self.expect(TokenType.LPAREN)

        saved_pos = self.pos
        if self.match(TokenType.IDENTIFIER):
            first = self.advance()
            if self.match(TokenType.IDENTIFIER) and self.current().value == 'in':
                self.advance()
                iterable = self.parse_expression()
                self.expect(TokenType.RPAREN)
                body = self._parse_brace_block()
                return ForStatement(init=None, condition=None, update=None, body=body,
                                    is_foreach=True, var_name=first.value, iterable=iterable)
            self.pos = saved_pos

        init = None
        if not self.match(TokenType.SEMICOLON):
            if self.match(TokenType.STRING_TYPE, TokenType.INT_TYPE, TokenType.FLOAT_TYPE,
                          TokenType.BOOL_TYPE, TokenType.LIST_TYPE):
                init = self.parse_var_decl()
            else:
                init = self.parse_expression()
        if self.match(TokenType.SEMICOLON):
            self.advance()

        condition = None
        if not self.match(TokenType.SEMICOLON):
            condition = self.parse_expression()
        self.expect(TokenType.SEMICOLON)

        update = None
        if not self.match(TokenType.RPAREN):
            update = self.parse_expression()
        self.expect(TokenType.RPAREN)
        body = self._parse_brace_block()

        return ForStatement(init=init, condition=condition, update=update, body=body, is_foreach=False)

    def parse_while(self) -> WhileStatement:
        self.expect(TokenType.WHILE)
        self.expect(TokenType.LPAREN)
        condition = self.parse_expression()
        self.expect(TokenType.RPAREN)
        body = self._parse_brace_block()
        return WhileStatement(condition=condition, body=body)

    def parse_return(self) -> ReturnStatement:
        self.expect(TokenType.RETURN)
        value = None
        if not self.match(TokenType.SEMICOLON, TokenType.RBRACE, TokenType.NEWLINE):
            value = self.parse_expression()
        self._skip_optional_semicolon()
        return ReturnStatement(value=value)

    def parse_fails(self) -> FailsTask:
        self.expect(TokenType.FAILS)
        self.expect(TokenType.LPAREN)
        task_call = self.parse_task_call()
        self.expect(TokenType.RPAREN)
        self._skip_optional_semicolon()
        return FailsTask(task_call=task_call)

    # Expression parsing - precedence climbing

    def parse_expression(self) -> ASTNode:
        return self.parse_or()

    def parse_or(self) -> ASTNode:
        left = self.parse_and()
        while self.match(TokenType.OR):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_and())
        return left

    def parse_and(self) -> ASTNode:
        left = self.parse_equality()
        while self.match(TokenType.AND):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_equality())
        return left

    def parse_equality(self) -> ASTNode:
        left = self.parse_comparison()
        while self.match(TokenType.EQ, TokenType.NEQ):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_comparison())
        return left

    def parse_comparison(self) -> ASTNode:
        left = self.parse_additive()
        while self.match(TokenType.LT, TokenType.GT, TokenType.LTE, TokenType.GTE):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_additive())
        return left

    def parse_additive(self) -> ASTNode:
        left = self.parse_multiplicative()
        while self.match(TokenType.PLUS, TokenType.MINUS, TokenType.PERCENT):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_multiplicative())
        return left

    def parse_multiplicative(self) -> ASTNode:
        left = self.parse_unary()
        while self.match(TokenType.STAR, TokenType.SLASH):
            op = self.advance().value
            left = BinaryOp(op=op, left=left, right=self.parse_unary())
        return left

    def parse_unary(self) -> ASTNode:
        if self.match(TokenType.NOT, TokenType.MINUS):
            op = self.advance().value
            return UnaryOp(op=op, operand=self.parse_unary())
        return self.parse_postfix()

    def parse_postfix(self) -> ASTNode:
        expr = self.parse_primary()
        while True:
            if self.match(TokenType.LPAREN):
                self.advance()
                args, kwargs = self.parse_arguments()
                self.expect(TokenType.RPAREN)
                if isinstance(expr, Identifier):
                    if expr.name in ('len', 'contains', 'equals', 'exists', 'fail'):
                        expr = FunctionCall(name=expr.name, args=args, kwargs=kwargs)
                    else:
                        expr = TaskCall(name=expr.name, args=args, kwargs=kwargs)
                else:
                    expr = FunctionCall(
                        name=expr.name if hasattr(expr, 'name') else str(expr),
                        args=args, kwargs=kwargs
                    )
            elif self.match(TokenType.LBRACKET):
                self.advance()
                index = self.parse_expression()
                self.expect(TokenType.RBRACKET)
                expr = ArrayAccess(array=expr, index=index)
            elif self.match(TokenType.DOT):
                self.advance()
                member = self.expect(TokenType.IDENTIFIER).value
                if isinstance(expr, Identifier):
                    expr = Identifier(name=f"{expr.name}.{member}")
                else:
                    expr = Identifier(name=f"?.{member}")
            else:
                break
        return expr

    def parse_primary(self) -> ASTNode:
        if self.match(TokenType.INT):
            return Literal(self.advance().value)
        if self.match(TokenType.FLOAT):
            return Literal(self.advance().value)
        if self.match(TokenType.STRING):
            value = self.advance().value
            if '${' in value:
                return self.parse_template_string(value)
            return Literal(value)
        if self.match(TokenType.TRUE):
            self.advance()
            return Literal(True)
        if self.match(TokenType.FALSE):
            self.advance()
            return Literal(False)
        if self.match(TokenType.LBRACKET):
            return self.parse_list_literal_expr()
        if self.match(TokenType.LPAREN):
            self.advance()
            expr = self.parse_expression()
            self.expect(TokenType.RPAREN)
            return expr
        if self.match(TokenType.IDENTIFIER):
            name = self.advance().value
            if name == 'params' and self.match(TokenType.DOT):
                self.advance()
                return ParameterAccess(param_name=self.expect(TokenType.IDENTIFIER).value)
            if name == 'workspace':
                return WorkspaceAccess()
            return Identifier(name=name)

        raise self.error(f"Unexpected token in expression: {self.current().type.name}")

    def parse_template_string(self, value: str) -> TemplateString:
        parts = []
        i = 0
        current = ""

        while i < len(value):
            if i + 1 < len(value) and value[i:i+2] == '${':
                if current:
                    parts.append(current)
                    current = ""
                j = i + 2
                brace_count = 1
                while j < len(value) and brace_count > 0:
                    if value[j] == '{':
                        brace_count += 1
                    elif value[j] == '}':
                        brace_count -= 1
                    j += 1
                parts.append(self._parse_template_expr(value[i+2:j-1]))
                i = j
            else:
                current += value[i]
                i += 1

        if current:
            parts.append(current)
        return TemplateString(parts=parts)

    def _parse_template_expr(self, expr_str: str) -> ASTNode:
        expr_str = expr_str.strip()
        if expr_str == 'workspace':
            return WorkspaceAccess()
        if expr_str.startswith('params.'):
            return ParameterAccess(param_name=expr_str[7:])
        if not any(c in expr_str for c in '(){}[];:=+-*/%<>!&|'):
            return TemplateString(['${' + expr_str + '}'])
        lexer = Lexer(expr_str)
        tokens = lexer.filter_tokens(lexer.tokenize())
        return Parser(tokens, self.run_blocks).parse_expression()

    def parse_list_literal_expr(self) -> ListLiteral:
        self.expect(TokenType.LBRACKET)
        elements = []
        while not self.match(TokenType.RBRACKET, TokenType.EOF):
            elements.append(self.parse_expression())
            if self.match(TokenType.COMMA):
                self.advance()
        self.expect(TokenType.RBRACKET)
        return ListLiteral(elements)

    def parse_arguments(self) -> Tuple[List[ASTNode], Dict[str, ASTNode]]:
        args, kwargs = [], []
        while not self.match(TokenType.RPAREN, TokenType.EOF):
            if self.match(TokenType.IDENTIFIER) and self.peek(1).type == TokenType.ASSIGN:
                name = self.advance().value
                self.advance()  # =
                kwargs.append((name, self.parse_expression()))
            else:
                args.append(self.parse_expression())
            if self.match(TokenType.COMMA):
                self.advance()
        return args, dict(kwargs)

    def parse_task_call(self) -> TaskCall:
        name = self.expect(TokenType.IDENTIFIER).value
        self.expect(TokenType.LPAREN)
        args, kwargs = self.parse_arguments()
        self.expect(TokenType.RPAREN)
        return TaskCall(name=name, args=args, kwargs=kwargs)


def preprocess_pipeline(source: str) -> Tuple[str, Dict[str, str]]:
    """Extract run block contents from source, replacing each with a placeholder."""
    run_blocks: Dict[str, str] = {}
    result = []
    i = 0

    while i < len(source):
        if source[i:i+3] != 'run':
            result.append(source[i])
            i += 1
            continue

        brace_start = _find_run_brace_start(source, i + 3)
        if brace_start is None:
            result.append(source[i])
            i += 1
            continue

        end, content = _extract_brace_content(source, brace_start)
        placeholder = f'__RUN_BLOCK_{len(run_blocks)}__'
        run_blocks[placeholder] = content
        result.append(source[i:brace_start + 1])
        result.append(placeholder + ' }')
        i = end

    return ''.join(result), run_blocks


def _find_run_brace_start(source: str, j: int) -> Optional[int]:
    while j < len(source) and source[j] in ' \t\n':
        j += 1
    if j < len(source) and source[j] == '{':
        return j
    if j < len(source) and source[j] == ':':
        j += 1
        while j < len(source) and source[j] in ' \t\n':
            j += 1
        if j < len(source) and source[j] == '{':
            return j
    return None


def _extract_brace_content(source: str, brace_start: int) -> Tuple[int, str]:
    k = brace_start + 1
    depth = 1
    while k < len(source) and depth > 0:
        if source[k] == '{':
            depth += 1
        elif source[k] == '}':
            depth -= 1
        elif source[k] in ('"', "'"):
            quote = source[k]
            k += 1
            while k < len(source) and source[k] != quote:
                if source[k] == '\\':
                    k += 1
                k += 1
        elif source[k:k+2] == '//':
            while k < len(source) and source[k] != '\n':
                k += 1
        k += 1

    return k, source[brace_start + 1:k - 1].strip()


def parse_pipeline(source: str) -> Pipeline:
    preprocessed, run_blocks = preprocess_pipeline(source)
    lexer = Lexer(preprocessed)
    tokens = lexer.filter_tokens(lexer.tokenize())
    return Parser(tokens, run_blocks).parse()

